// Tag rules: map workflow name patterns to tags
// Adjust these to match your naming conventions
const TAG_RULES = [
  { pattern: /drive|gdrive|google.?drive/i, tag: 'google-drive' },
  { pattern: /sheet|spreadsheet/i, tag: 'google-sheets' },
  { pattern: /email|gmail|mail/i, tag: 'email' },
  { pattern: /slack/i, tag: 'slack' },
  { pattern: /zoho/i, tag: 'zoho' },
  { pattern: /webhook/i, tag: 'webhook' },
  { pattern: /cron|schedule|daily|weekly|hourly/i, tag: 'scheduled' },
  { pattern: /backup|sync|mirror/i, tag: 'backup' },
  { pattern: /test|debug|dev/i, tag: 'testing' },
  { pattern: /client|customer|crm/i, tag: 'clients' },
  { pattern: /invoice|billing|payment/i, tag: 'finance' },
  { pattern: /report|analytics|dashboard/i, tag: 'reporting' },
  { pattern: /n8n|cleanup|maintain/i, tag: 'maintenance' },
  { pattern: /tas|fdnxt/i, tag: 'TAS' },
];

// Folder rules: group workflows into logical folders
const FOLDER_RULES = [
  { pattern: /drive|gdrive|sheet|spreadsheet|google/i, folder: 'Google Workspace' },
  { pattern: /email|gmail|slack|communication/i, folder: 'Communications' },
  { pattern: /zoho|crm|client|customer/i, folder: 'CRM' },
  { pattern: /invoice|billing|payment|finance/i, folder: 'Finance' },
  { pattern: /backup|sync|mirror/i, folder: 'Sync & Backup' },
  { pattern: /test|debug|dev|experiment/i, folder: 'Development' },
  { pattern: /report|analytics|dashboard/i, folder: 'Reporting' },
  { pattern: /n8n|cleanup|maintain|cron|schedule/i, folder: 'System & Maintenance' },
];

const workflows = $input.first().json.data || [];
const results = [];

for (const wf of workflows) {
  const matchedTags = [];
  let matchedFolder = 'Uncategorised';

  // Match tags
  for (const rule of TAG_RULES) {
    if (rule.pattern.test(wf.name)) {
      matchedTags.push(rule.tag);
    }
  }

  // Match folder (first match wins)
  for (const rule of FOLDER_RULES) {
    if (rule.pattern.test(wf.name)) {
      matchedFolder = rule.folder;
      break;
    }
  }

  // Check existing tags
  const existingTags = (wf.tags || []).map(t => t.name);
  const newTags = matchedTags.filter(t => !existingTags.includes(t));

  results.push({
    id: wf.id,
    name: wf.name,
    active: wf.active,
    existingTags,
    newTags,
    allTags: [...new Set([...existingTags, ...matchedTags])],
    folder: matchedFolder,
    needsUpdate: newTags.length > 0
  });
}

return results.map(r => ({ json: r }));

// Ensure tags exist in n8n, then apply to workflow
const BASE_URL = $env.N8N_BASE_URL;
const API_KEY = $env.N8N_API_KEY;
const wf = $input.first().json;

// Step 1: Get all existing tags
const tagsResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${BASE_URL}/api/v1/tags`,
  headers: { 'X-N8N-API-KEY': API_KEY }
});
const existingTags = tagsResp.data || tagsResp || [];
const tagMap = {};
for (const t of existingTags) {
  tagMap[t.name] = t.id;
}

// Step 2: Create any missing tags
for (const tagName of wf.newTags) {
  if (!tagMap[tagName]) {
    try {
      const created = await this.helpers.httpRequest({
        method: 'POST',
        url: `${BASE_URL}/api/v1/tags`,
        headers: { 'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json' },
        body: { name: tagName }
      });
      tagMap[tagName] = created.id;
    } catch (err) {
      // Tag might already exist
    }
  }
}

// Step 3: Update workflow with all tags
const tagIds = wf.allTags.map(t => tagMap[t]).filter(Boolean);
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${BASE_URL}/api/v1/workflows/${wf.id}`,
    headers: { 'X-N8N-API-KEY': API_KEY, 'Content-Type': 'application/json' },
    body: { tags: tagIds.map(id => ({ id })) }
  });
} catch (err) {
  return [{ json: { ...wf, tagUpdateStatus: 'FAILED', error: err.message } }];
}

return [{ json: { ...wf, tagUpdateStatus: 'OK', appliedTags: wf.allTags } }];

// Build a summary report of all workflows grouped by folder
const items = $input.all();
const folders = {};

for (const item of items) {
  const wf = item.json;
  const folder = wf.folder || 'Uncategorised';
  if (!folders[folder]) folders[folder] = [];
  folders[folder].push({
    name: wf.name,
    id: wf.id,
    active: wf.active,
    tags: wf.allTags || wf.existingTags || [],
    needsUpdate: wf.needsUpdate
  });
}

const folderSummary = Object.entries(folders).map(([name, workflows]) => ({
  folder: name,
  count: workflows.length,
  workflows
})).sort((a, b) => b.count - a.count);

return [{
  json: {
    totalWorkflows: items.length,
    totalFolders: folderSummary.length,
    taggedCount: items.filter(i => i.json.needsUpdate).length,
    folders: folderSummary,
    runAt: new Date().toISOString()
  }
}];
